// AI Provider toggle: "openai" = direct OpenAI, "replit" = Replit AI proxy
let contentAIProvider: "openai" | "replit" = "openai";

export function setContentAIProvider(provider: "openai" | "replit") {
  contentAIProvider = provider;
  console.log(`[AI Provider] Content generation now using: ${provider === "replit" ? "Replit AI" : "OpenAI"}`);
}

export function getContentAIProvider(): "openai" | "replit" {
  return contentAIProvider;
}

function getContentClient(): OpenAI {
  if (contentAIProvider === "replit") {
    return openaiReplit;
  }
  return openai;
}

function getFallbackClient(): OpenAI {
  return openai;
}

function getSecondFallbackClient(): OpenAI {
  return openaiReplit;
}

async function callAIProvider(prompt: string, temperature: number, maxTokens: number): Promise<string> {
  const response = await getContentClient().chat.completions.create({
    model: "gpt-4o-mini",
    messages: [{ role: "user", content: prompt }],
    temperature,
    max_tokens: maxTokens,
  });
  return response.choices[0]?.message?.content || "";
}

/**
 * Stream long gpt-5.2 completions. Non-streaming chapter calls often die at ~60s on
 * Windows/Cloudflare paths (UND_ERR_SOCKET / "other side closed") while streaming works.
 */
async function streamChatCompletion(options: {
  client?: OpenAI;
  model?: string;
  messages: Array<{ role: "system" | "user" | "assistant"; content: string }>;
  max_completion_tokens: number;
}): Promise<{ content: string; finishReason: string | null }> {
  const client = options.client ?? getContentClient();
  const stream = await client.chat.completions.create({
    model: options.model ?? "gpt-5.2",
    messages: options.messages,
    max_completion_tokens: options.max_completion_tokens,
    stream: true,
  });
  let content = "";
  let finishReason: string | null = null;
  for await (const chunk of stream) {
    const choice = chunk.choices?.[0];
    if (choice?.delta?.content) content += choice.delta.content;
    if (choice?.finish_reason) finishReason = choice.finish_reason;
  }
  return { content, finishReason };
}

function formatOpenAIError(error: any): string {
  const nested = error?.cause?.cause || error?.cause;
  const code = nested?.code || error?.code;
  const detail = nested?.message || error?.cause?.message;
  if (code || detail) return `${error?.message || "error"}${code ? ` [${code}]` : ""}${detail ? ` — ${detail}` : ""}`;
  return error?.message || String(error);
}

/** Transport/network failures that retrying will only burn money — dig deeper after 2. */
function isTransportFailure(error: any): boolean {
  const msg = String(error?.message || "").toLowerCase();
  const nested = error?.cause?.cause || error?.cause;
  const code = String(nested?.code || error?.code || "");
  return (
    msg.includes("connection error") ||
    msg.includes("fetch failed") ||
    msg.includes("timeout") ||
    msg.includes("econnreset") ||
    msg.includes("socket") ||
    code === "UND_ERR_SOCKET" ||
    code === "ECONNRESET" ||
    code === "ETIMEDOUT" ||
    code === "ENOTFOUND"
  );
}

class TransportAbortError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "TransportAbortError";
  }
}

const REFUSAL_PATTERNS = [
  /^I can(?:'t| not) (?:create|write|generate|produce|help|build|draft)/i,
  /^I'm (?:not able to|unable to|sorry,? (?:but )?I can(?:'t| not))/i,
  /I (?:can(?:'t| not)|won't|will not) (?:help )?(?:plan|depict|write|create|generate).*(?:sexual|explicit|violence|coercion|assault)/i,
  /sexual (?:coercion|violence|assault) is/i,
  /I'm not comfortable/i,
  /against (?:my|our) (?:content |usage )?polic/i,
];

function detectRefusal(text: string): boolean {
  const firstParagraph = text.substring(0, 500);
  return REFUSAL_PATTERNS.some(p => p.test(firstParagraph));
}

