  const positions = ["top", "top-left", "top-right", "center", "bottom", "bottom-left", "bottom-right"];
  const colors = ["#FFFFFF", "#FFD700", "#E74C3C", "#9B59B6", "#1ABC9C", "#FF9800", "#00CED1", "#E91E63", "#3498DB"];
